Javascript.logic:
try{
	var sourceEvent = event.getXPath()
	if ((sourceEvent == Hearing2AtThisOfficeAddress.dataBinding) || (sourceEvent == REF_DATA_XPATH + "/OwningCourt/Courts[position() = 1]"))
	{
		var thisOffice = Services.getValue(Hearing2AtThisOfficeAddress.dataBinding);
		if (!CaseManUtils.isBlank(thisOffice))
		{
			if (thisOffice == "Y")
			{
				var officeAddressExists = Services.exists(REF_DATA_XPATH + "/OwningCourt/Courts/Court/ContactDetails/Address[./AddressType = 'OFFICE']");
				if ( officeAddressExists )
				{
					// Use court office address
					var rootXpath =  REF_DATA_XPATH + "/OwningCourt/Courts/Court/ContactDetails/Address[./AddressType = 'OFFICE']";
				}
				else
				{
					// No court office address so use the first address returned
					var rootXpath = REF_DATA_XPATH + "/OwningCourt/Courts/Court/ContactDetails/Address[1]";
				}
				// Retrieve the address fields
				var name = Services.getValue(REF_DATA_XPATH + "/OwningCourt/Courts/Court/Name");	
				var address1 = Services.getValue(rootXpath + "/Line[1]");	
				var address2 = Services.getValue(rootXpath + "/Line[2]");
				var address3 = Services.getValue(rootXpath + "/Line[3]");
				var address4 = Services.getValue(rootXpath + "/Line[4]");
				var address5 = Services.getValue(rootXpath + "/Line[5]");		
				var postCode = Services.getValue(rootXpath + "/PostCode");
				// Set the address fields
				Services.startTransaction();			
				Services.setValue(Hearing2Courtname.dataBinding, name);
				Services.setValue(Hearing2VenueAddressLine1.dataBinding, address1);
				Services.setValue(Hearing2VenueAddressLine2.dataBinding, address2);
				Services.setValue(Hearing2VenueAddressLine3.dataBinding, address3);
				Services.setValue(Hearing2VenueAddressLine4.dataBinding, address4);
				Services.setValue(Hearing2VenueAddressLine5.dataBinding, address5);
				Services.setValue(Hearing2VenuePostcode.dataBinding, postCode);
				Services.endTransaction();			
			}
		}
	}
}
catch(e)
{
	// Exception may arise depending upon the event. So do nothing.
}
